"use client";

import React, { useRef } from "react";
import Editor, { OnMount } from "@monaco-editor/react";

interface EditorPaneProps {
    value: string;
    onChange: (value: string | undefined) => void;
    language?: string;
}

export default function EditorPane({ value, onChange, language = "markdown" }: EditorPaneProps) {
    const editorRef = useRef<any>(null);

    const handleEditorDidMount: OnMount = (editor, monaco) => {
        editorRef.current = editor;

        // Define a custom theme that respects transparency
        monaco.editor.defineTheme('glass-dark', {
            base: 'vs-dark',
            inherit: true,
            rules: [],
            colors: {
                'editor.background': '#00000000', // Very important for glass effect
                'editorGutter.background': '#00000000',
                'editorLineNumber.foreground': '#555555',
            }
        });
        monaco.editor.setTheme('glass-dark');
    };

    return (
        <div className="h-full w-full overflow-hidden bg-transparent">
            {/* Note: The parent container in AppShell already has glass-panel utility if needed, 
                 but for the editor itself, we want it clean. */}
            <Editor
                height="100%"
                defaultLanguage={language}
                defaultValue={value}
                value={value}
                onChange={onChange}
                theme="glass-dark"
                onMount={handleEditorDidMount}
                loading={<div className="text-muted-foreground text-sm p-4">Loading Editor...</div>}
                options={{
                    minimap: { enabled: false },
                    fontSize: 15,
                    fontFamily: "'Fira Code', 'Cascadia Code', Consolas, monospace",
                    wordWrap: "on",
                    padding: { top: 20, bottom: 20 },
                    scrollBeyondLastLine: false,
                    smoothScrolling: true,
                    cursorBlinking: "smooth",
                    cursorSmoothCaretAnimation: "on",
                    formatOnPaste: true,
                    formatOnType: true,
                    lineNumbers: "on",
                    glyphMargin: false,
                    folding: false,
                    lineDecorationsWidth: 10,
                    lineNumbersMinChars: 3,
                    renderLineHighlight: "none", // Cleaner look
                }}
            />
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";

export interface AppSettings {
    mistralApiKey: string;
    githubApiKey: string;
    githubRepo: string; // "owner/repo"
    selectedModel: string;
}

const DEFAULT_SETTINGS: AppSettings = {
    mistralApiKey: "",
    githubApiKey: "",
    githubRepo: "",
    selectedModel: "voxtral-mini", // default per plan
};

export function useSettings() {
    const [settings, setSettings] = useState<AppSettings>(() => {
        if (typeof window !== "undefined") {
            const saved = localStorage.getItem("mistral-notes-settings");
            if (saved) {
                try {
                    return { ...DEFAULT_SETTINGS, ...JSON.parse(saved) };
                } catch (e) {
                    console.error("Failed to parse settings", e);
                }
            }
        }
        return DEFAULT_SETTINGS;
    });
    const [loading] = useState(false);

    const updateSettings = (newSettings: Partial<AppSettings>) => {
        setSettings((prev) => {
            const next = { ...prev, ...newSettings };
            localStorage.setItem("mistral-notes-settings", JSON.stringify(next));
            return next;
        });
    };

    return { settings, updateSettings, loading };
}

import { Octokit } from "octokit";

export const getOctokit = (token: string) => {
    if (!token) return null;
    return new Octokit({ auth: token });
};

export interface FileItem {
    name: string;
    path: string;
    type: "file" | "dir";
    sha: string;
}

export const listRepoFiles = async (token: string, owner: string, repo: string, path = ""): Promise<FileItem[]> => {
    const octokit = getOctokit(token);
    if (!octokit) return [];

    try {
        const { data } = await octokit.rest.repos.getContent({
            owner,
            repo,
            path,
        });

        if (Array.isArray(data)) {
            return data
                .filter((item) => item.type === "file" || item.type === "dir")
                .map((item) => ({
                    name: item.name,
                    path: item.path,
                    type: item.type as "file" | "dir",
                    sha: item.sha
                }));
        }
        return [];
    } catch (e) {
        console.error("Failed to list files", e);
        return [];
    }
};

export const getFileContent = async (token: string, owner: string, repo: string, path: string): Promise<string> => {
    const octokit = getOctokit(token);
    if (!octokit) return "";
    try {
        const { data } = await octokit.rest.repos.getContent({
            owner,
            repo,
            path,
        });

        if ('content' in data) {
            return atob(data.content); // basic base64 decode for small files
        }
        return "";
    } catch {
        // console.error("Failed to get content", e);
        return "";
    }
};

export const saveFileContent = async (token: string, owner: string, repo: string, path: string, content: string, sha?: string) => {
    const octokit = getOctokit(token);
    if (!octokit) throw new Error("No token");

    try {
        // If sha not provided, try to get it first (for update)
        let fileSha = sha;
        if (!fileSha) {
            try {
                const { data } = await octokit.rest.repos.getContent({ owner, repo, path });
                if ('sha' in data) fileSha = data.sha;
            } catch (e) {
                // File might not exist, which is fine for create
            }
        }

        await octokit.rest.repos.createOrUpdateFileContents({
            owner,
            repo,
            path,
            message: `Update ${path} via Mistral Notes`,
            content: btoa(content), // buffer conversion validation needed for unicode
            sha: fileSha,
        });
    } catch (e) {
        console.error("Failed to save file", e);
        throw e;
    }
};
